import { client } from "@trigger.dev/sdk";
import { aiContentGenerator } from "../src/trigger/ai-generator";

async function main() {
  try {
    // Trigger the task
    const run = await client.sendEvent({
      name: "ai-content-generation",
      id: aiContentGenerator.id,
      payload: {},
    });

    // Print the run ID
    console.log(`Run ID: ${run.id}`);
  } catch (error) {
    console.error("Error triggering task:", error);
    process.exit(1);
  }
}

main();

import { client } from "@trigger.dev/sdk";

async function main() {
  // Get run ID from command line arguments
  const runId = process.argv[2];

  if (!runId) {
    console.error("Error: Run ID is required");
    console.error("Usage: npm run cancel-task -- <runId>");
    process.exit(1);
  }

  try {
    // Cancel the task
    await client.cancelRun(runId);

    console.log(`Task ${runId} has been cancelled successfully`);
  } catch (error) {
    console.error("Error cancelling task:", error);
    process.exit(1);
  }
}

main();

import { defineConfig } from "@trigger.dev/sdk";

export default defineConfig({
  // (Required) Your project ref from the Trigger.dev dashboard
  project: process.env.TRIGGER_PROJECT_REF,
  // (Required) Directories containing your tasks
  dirs: ["./src/trigger"],
  // (Required) Max duration of a task in seconds
  maxDuration: 3600,
  // (Optional) Retries config
  retries: {
    enabledInDev: true,
    default: {
      maxAttempts: 2,
      minTimeoutInMs: 1000,
      maxTimeoutInMs: 10000,
      factor: 2,
      randomize: true,
    },
  },
});

